test_numbers = list(range(1, len(ass2FixSteps) + 1))

plt.rcParams.update({
    "font.family": "serif",
    "font.size": 12,
    "axes.spines.top": False,
    "axes.spines.right": False,
})

COLOR_OPTIMIZED           = "#1d8348"
COLOR_OPTIMIZED_HEURISTIC = "#053d63"
COLOR_BASIC               = "#cb4335"
COLOR_BASIC_HEURISTIC     = "#e59866"
BG                        = "#fafafa"

def make_chart(fig_data, ylabel, title, filename, fmt_y):
    fig, ax = plt.subplots(figsize=(14, 7))
    fig.patch.set_facecolor(BG)
    ax.set_facecolor(BG)

    for data, color, label, ls in fig_data:
        ax.plot(test_numbers, data, color=color, linewidth=2, alpha=0.95, label=label, linestyle=ls)
        ax.fill_between(test_numbers, data, alpha=0.05, color=color)

    ax.set_xlabel("Test Number", fontsize=13, labelpad=10, color="#2c2c2c")
    ax.set_ylabel(ylabel, fontsize=13, labelpad=10, color="#2c2c2c")
    ax.set_title(title, fontsize=15, fontweight="bold", pad=20, color="#1a1a1a")
    ax.tick_params(colors="#555555")
    ax.xaxis.set_major_locator(ticker.MultipleLocator(100))
    ax.yaxis.set_major_formatter(ticker.FuncFormatter(fmt_y))
    ax.grid(True, linestyle="--", linewidth=0.5, alpha=0.4, color="#aaaaaa")

    offsets = [(-110, -50), (-110, -35), (-110, 15), (-110, 30)]
    for (data, color, label, ls), offset in zip(fig_data, offsets):
        if fmt_y(data[-1], None).endswith("s"):
            ann_label = f"Total: {data[-1]:.2f}s"
        else:
            ann_label = f"Total: {data[-1]:,}"
        ax.annotate(
            ann_label,
            xy=(test_numbers[-1], data[-1]),
            xytext=offset,
            textcoords="offset points",
            fontsize=10,
            color=color,
            arrowprops=dict(arrowstyle="-", color=color, lw=0.8),
        )

    ax.legend(frameon=False, fontsize=11, loc="upper left")
    plt.tight_layout(rect=[0, 0.03, 1, 1])
    plt.savefig(filename, dpi=300, bbox_inches="tight", facecolor=fig.get_facecolor())
    print(f"Saved: {filename}")
    return fig

steps_data = [
    (ass2FixSteps,          COLOR_OPTIMIZED,           "Optimized ",     "-"),
    (ass2FixHeuristicSteps, COLOR_OPTIMIZED_HEURISTIC, "Optimized + Heuristic",   "--"),
    (assiSteps,             COLOR_BASIC,               "Basic ",            "-"),
    (assiHeuristicSteps,    COLOR_BASIC_HEURISTIC,     "Basic + Heuristic",       "--"),
]

time_data = [
    (ass2FixTime,          COLOR_OPTIMIZED,           "Optimized ",     "-"),
    (ass2FixHeuristicTime, COLOR_OPTIMIZED_HEURISTIC, "Optimized + Heuristic",   "--"),
    (assiTime,             COLOR_BASIC,               "Basic ",            "-"),
    (assiHeuristicTime,    COLOR_BASIC_HEURISTIC,     "Basic + Heuristic",       "--"),
]

make_chart(steps_data, "Cumulative Rules Applied",   "Cumulative Rules Applied Across Benchmark Tests",   "steps_comparison.png", lambda x, _: f"{int(x):,}")
make_chart(time_data,  "Cumulative Time (seconds)",  "Cumulative Execution Time Across Benchmark Tests",  "time_comparison.png",  lambda x, _: f"{x:.1f}s")

plt.show()